import React, { useState } from 'react';
import { useBlockchain } from '../context/BlockchainContext';
import { ethers } from 'ethers';

const VerifierDashboard: React.FC = () => {
    const { isVerifier, contract } = useBlockchain();
    const [userAddress, setUserAddress] = useState('');
    const [documentHash, setDocumentHash] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    if (!isVerifier) {
        return <div style={{ padding: '2rem', textAlign: 'center', color: 'red' }}>Access Denied: Only approved verifiers can access this page.</div>;
    }

    const handleVerifyUser = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !userAddress || !documentHash) return;

        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.verifyUser(userAddress, documentHash);
            await tx.wait();
            setMessage(`Successfully verified user ${userAddress}.`);
            setDocumentHash('');
        } catch (error: any) {
            setMessage(`Error verifying user: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    const handleRevokeUser = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !userAddress) return;

        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.revokeUser(userAddress);
            await tx.wait();
            setMessage(`Successfully revoked verification for user ${userAddress}.`);
        } catch (error: any) {
            setMessage(`Error revoking user: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    const handleCheckHash = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !userAddress || !documentHash) return;

        setLoading(true);
        setMessage('');
        try {
            // Note: In Ethers v6, calling a state-changing function returns a transaction response, 
            // but we can use staticCall if we just want to read the return value without committing.
            // However, since it emits an event, we should call it normally if we want the event, or use callStatic.
            // Let's use callStatic to get the boolean without spending gas if possible, or just call it.
            const result = await contract.checkDocumentHash.staticCall(userAddress, documentHash);
            setMessage(result ? "Hash MATCHES the registered user document." : "Hash DOES NOT MATCH the registered document.");
        } catch (error: any) {
             setMessage(`Error checking hash: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
            <h2>Verifier Dashboard</h2>
            <p>Welcome Verifier. You can verify users, check document hashes, or revoke verifications.</p>

            <div style={{ padding: '1.5rem', border: '1px solid #ccc', borderRadius: '8px', marginTop: '2rem' }}>
                <h3>User Verification Tasks</h3>

                {message && (
                    <div style={{ padding: '1rem', marginBottom: '1rem', backgroundColor: message.includes('Error') || message.includes('DOES NOT MATCH') ? '#ffebee' : '#e8f5e9', borderRadius: '4px' }}>
                        {message}
                    </div>
                )}

                <form style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    <div>
                        <label style={{ display: 'block', marginBottom: '0.5rem' }}>User Ethereum Address:</label>
                        <input 
                            type="text" 
                            value={userAddress}
                            onChange={(e) => setUserAddress(e.target.value)}
                            placeholder="0x..."
                            style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
                            required
                        />
                    </div>
                    <div>
                        <label style={{ display: 'block', marginBottom: '0.5rem' }}>Document Hash (calculated off-chain):</label>
                        <input 
                            type="text" 
                            value={documentHash}
                            onChange={(e) => setDocumentHash(e.target.value)}
                            placeholder="Data hash to check/verify"
                            style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
                        />
                    </div>

                    <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', marginTop: '1rem' }}>
                        <button 
                            type="button" 
                            onClick={handleCheckHash}
                            disabled={loading || !userAddress || !documentHash}
                            style={{ flex: 1, padding: '0.75rem', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px', cursor: (loading || !userAddress || !documentHash) ? 'not-allowed' : 'pointer' }}
                        >
                            {loading ? 'Processing...' : '1. Check Hash Match'}
                        </button>
                        <button 
                            type="button" 
                            onClick={handleVerifyUser}
                            disabled={loading || !userAddress || !documentHash}
                            style={{ flex: 1, padding: '0.75rem', backgroundColor: '#4caf50', color: 'white', border: 'none', borderRadius: '4px', cursor: (loading || !userAddress || !documentHash) ? 'not-allowed' : 'pointer' }}
                        >
                            {loading ? 'Processing...' : '2. Verify User'}
                        </button>
                        <button 
                            type="button" 
                            onClick={handleRevokeUser}
                            disabled={loading || !userAddress}
                            style={{ flex: 1, minWidth: '100%', padding: '0.75rem', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px', cursor: (loading || !userAddress) ? 'not-allowed' : 'pointer' }}
                        >
                            {loading ? 'Processing...' : 'Revoke Verification'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default VerifierDashboard;
